import React, { useState } from 'react';
import './App.css';

// Amino acid monoisotopic masses
const aminoAcidMasses: Record<string, { mono: number; avg: number; formula: Record<string, number> }> = {
  'G': { mono: 57.02146, avg: 57.02146, formula: { C: 2, H: 3, N: 1, O: 1, S: 0 } },
  'A': { mono: 71.03711, avg: 71.0788, formula: { C: 3, H: 5, N: 1, O: 1, S: 0 } },
  'V': { mono: 99.06841, avg: 99.1326, formula: { C: 5, H: 9, N: 1, O: 1, S: 0 } },
  'L': { mono: 113.08406, avg: 113.1576, formula: { C: 6, H: 11, N: 1, O: 1, S: 0 } },
  'I': { mono: 113.08406, avg: 113.1576, formula: { C: 6, H: 11, N: 1, O: 1, S: 0 } },
  'P': { mono: 97.05276, avg: 97.1152, formula: { C: 5, H: 7, N: 1, O: 1, S: 0 } },
  'F': { mono: 147.06841, avg: 147.1739, formula: { C: 9, H: 9, N: 1, O: 1, S: 0 } },
  'W': { mono: 186.07931, avg: 186.2132, formula: { C: 11, H: 10, N: 2, O: 1, S: 0 } },
  'M': { mono: 131.04049, avg: 131.1961, formula: { C: 5, H: 9, N: 1, O: 1, S: 1 } },
  'S': { mono: 87.03203, avg: 87.0773, formula: { C: 3, H: 5, N: 1, O: 2, S: 0 } },
  'T': { mono: 101.04768, avg: 101.1039, formula: { C: 4, H: 7, N: 1, O: 2, S: 0 } },
  'C': { mono: 103.00919, avg: 103.1388, formula: { C: 3, H: 5, N: 1, O: 1, S: 1 } },
  'Y': { mono: 163.06333, avg: 163.1732, formula: { C: 9, H: 9, N: 1, O: 2, S: 0 } },
  'H': { mono: 137.05891, avg: 137.1393, formula: { C: 6, H: 7, N: 3, O: 1, S: 0 } },
  'D': { mono: 115.02694, avg: 115.0886, formula: { C: 4, H: 5, N: 1, O: 3, S: 0 } },
  'E': { mono: 129.04259, avg: 129.1155, formula: { C: 5, H: 7, N: 1, O: 3, S: 0 } },
  'N': { mono: 114.04293, avg: 114.1026, formula: { C: 4, H: 6, N: 2, O: 2, S: 0 } },
  'Q': { mono: 128.05858, avg: 128.1292, formula: { C: 5, H: 8, N: 2, O: 2, S: 0 } },
  'K': { mono: 128.09496, avg: 128.1724, formula: { C: 6, H: 12, N: 2, O: 1, S: 0 } },
  'R': { mono: 156.10111, avg: 156.1857, formula: { C: 6, H: 12, N: 4, O: 1, S: 0 } }
};

interface CalculationResult {
  sequence: string;
  length: number;
  monoMW: number;
  avgMW: number;
  formula: Record<string, number>;
}

function calculateMW(sequence: string): CalculationResult {
  const seq = sequence.toUpperCase().trim();
  let monoMW = 0;
  let avgMW = 0;
  const formula: Record<string, number> = { C: 0, H: 0, N: 0, O: 0, S: 0 };

  for (const aa of seq) {
    const data = aminoAcidMasses[aa];
    if (data) {
      monoMW += data.mono;
      avgMW += data.avg;
      formula.C += data.formula.C;
      formula.H += data.formula.H;
      formula.N += data.formula.N;
      formula.O += data.formula.O;
      formula.S += data.formula.S;
    }
  }

  // Add water (H2O) for terminal groups
  monoMW += 18.01056;
  avgMW += 18.01528;
  formula.H += 2;
  formula.O += 1;

  return {
    sequence: seq,
    length: seq.length,
    monoMW,
    avgMW,
    formula
  };
}

const App: React.FC = () => {
  const [sequence, setSequence] = useState('OXYTOCIN');
  const [result, setResult] = useState<CalculationResult | null>(null);
  const [error, setError] = useState('');

  const handleCalculate = () => {
    setError('');

    if (!sequence.trim()) {
      setError('Please enter a peptide sequence');
      return;
    }

    const validChars = /^[ACDEFGHIKLMNPQRSTVWY]+$/;
    if (!validChars.test(sequence.toUpperCase())) {
      setError('Invalid characters. Use only: A C D E F G H I K L M N P Q R S T V W Y');
      return;
    }

    const calcResult = calculateMW(sequence);
    setResult(calcResult);
  };

  const examples = ['OXYTOCIN', 'GLUTATHIONE', 'INSULIN', 'ACDEFGHIKLMNPQRSTVWY', 'AAAAAAAAAA'];

  return (
    <div className="app">
      <header className="header">
        <h1>Peptide MW Calculator</h1>
        <p>Calculate molecular weight from amino acid sequence</p>
      </header>

      <main className="main">
        <div className="input-group">
          <label htmlFor="sequence">Peptide Sequence</label>
          <input
            id="sequence"
            type="text"
            value={sequence}
            onChange={(e) => setSequence(e.target.value)}
            placeholder="Enter sequence (e.g., ACDEFGHIKLMNPQRSTVWY)"
            maxLength={100}
            onKeyPress={(e) => e.key === 'Enter' && handleCalculate()}
          />
        </div>

        <button className="btn" onClick={handleCalculate}>
          Calculate Molecular Weight
        </button>

        {error && <div className="error">{error}</div>}

        {result && (
          <div className="result">
            <h3>Results</h3>
            <div className="result-row">
              <span className="result-label">Sequence:</span>
              <span className="result-value">{result.sequence}</span>
            </div>
            <div className="result-row">
              <span className="result-label">Length:</span>
              <span className="result-value">{result.length} amino acids</span>
            </div>
            <div className="result-row">
              <span className="result-label">Monoisotopic MW:</span>
              <span className="result-value">{result.monoMW.toFixed(4)} Da</span>
            </div>
            <div className="result-row">
              <span className="result-label">Average MW:</span>
              <span className="result-value">{result.avgMW.toFixed(4)} Da</span>
            </div>
            <div className="result-row">
              <span className="result-label">Molecular Formula:</span>
              <span className="result-value">
                C{result.formula.C}H{result.formula.H}N{result.formula.N}O{result.formula.O}S{result.formula.S}
              </span>
            </div>
          </div>
        )}

        <div className="examples">
          <h4>Try these examples:</h4>
          <div className="example-buttons">
            {examples.map((ex) => (
              <button
                key={ex}
                className="example-btn"
                onClick={() => {
                  setSequence(ex);
                  setResult(calculateMW(ex));
                }}
              >
                {ex}
              </button>
            ))}
          </div>
        </div>
      </main>

      <footer className="footer">
        <p>
          Based on <a href="https://wikipept.com" target="_blank" rel="noopener noreferrer">WikiPept</a> data
        </p>
        <p>
          <a href="https://encyclopeptide.com" target="_blank" rel="noopener noreferrer">Encyclopeptide</a> | 
          <a href="https://kingstonpeptides.com" target="_blank" rel="noopener noreferrer">Kingston Peptides</a>
        </p>
      </footer>
    </div>
  );
};

export default App;

